#!/usr/bin/env python3
"""
Radha Naam Jap — Automatic HTML Patcher v5→v6
Usage: python3 patch_v6.py index.html
Output: index_v6.html (ready for GitHub)
"""
import sys, re

SPLASH_B64 = """"""

ICON_B64 = """"""

FB_WRITE_SESSION = "async function fbWriteActiveSession() {\n  if (!fbUser) return;\n  try {\n    const docRef = fbDb.collection('users').doc(fbUser.uid).collection('data').doc('main');\n    await docRef.set({ activeSession: fbDeviceId }, { merge: true });\n  } catch(e) { console.warn('fbWriteActiveSession:', e.message); }\n}\n\nfunction fbAutoSync() {"

FB_APPLY_REMOTE = "function fbApplyRemote(d) {\n  // ── ONE DEVICE AT A TIME ──\n  if (d.activeSession && d.activeSession !== fbDeviceId) {\n    if (fbListener) { fbListener(); fbListener = null; }\n    gdAccessToken = null;\n    localStorage.removeItem('rjap_gd_token');\n    fbAuth.signOut().then(() => {\n      document.getElementById('fbLoggedOut').style.display = 'block';\n      document.getElementById('fbLoggedIn').style.display = 'none';\n      toast('⚠️ Signed out — another device logged in');\n      setTimeout(() => {\n        const el = document.getElementById('fbErr');\n        if (el) { el.textContent = 'You were signed out because another device signed in.'; setTimeout(() => el.textContent = '', 9000); }\n      }, 600);\n    });\n    return;\n  }\n  if (d.deviceId && d.deviceId === fbDeviceId) return;"

FB_PAYLOAD = '  const payload = {\n    history: App.S.history||{}, h28: App.S.h28||{}, stotrams: App.S.stotrams||{},\n    brahma: App.S.brahma||{}, customSt: App.S.customSt||[], timerHistory: App.S.timerHistory||{},\n    sankalpas: App.S.sankalpas||[], occasions: App.S.occasions||{},\n    ms: App.S.ms||108, dt: App.S.dt||0, lt: App.S.lt||0, cfg: App.S.cfg||{},\n    lastSync: firebase.firestore.FieldValue.serverTimestamp(),\n    deviceId: fbDeviceId, activeSession: fbDeviceId\n  };'

PWA_MANIFEST = 'function buildPwaManifest(){\n  const img=document.getElementById(\'pwaIconImg\');\n  const splashImg=document.getElementById(\'guruImg\');\n  function attach(){\n    try{\n      const c=document.createElement(\'canvas\');c.width=c.height=512;\n      const ctx=c.getContext(\'2d\');\n      ctx.fillStyle=\'#060D1F\';ctx.fillRect(0,0,512,512);\n      const aspect=(img.naturalWidth||1)/(img.naturalHeight||1);\n      let sw=512,sh=512/aspect;\n      if(sh>512){sh=512;sw=512*aspect;}\n      const sx=(512-sw)/2,sy=(512-sh)/2;\n      ctx.drawImage(img,sx,sy,sw,sh);\n      ctx.strokeStyle=\'rgba(255,215,0,0.55)\';ctx.lineWidth=12;\n      ctx.strokeRect(6,6,500,500);\n      const iconUrl=c.toDataURL(\'image/png\');\n\n      const c2=document.createElement(\'canvas\');c2.width=c2.height=512;\n      const ctx2=c2.getContext(\'2d\');\n      ctx2.fillStyle=\'#060D1F\';ctx2.fillRect(0,0,512,512);\n      ctx2.save();ctx2.beginPath();ctx2.arc(256,256,256,0,Math.PI*2);ctx2.clip();\n      const s2=Math.min(splashImg.naturalWidth||512,splashImg.naturalHeight||512);\n      ctx2.drawImage(splashImg,(splashImg.naturalWidth-s2)/2,0,s2,s2,0,0,512,512);\n      ctx2.restore();\n      ctx2.strokeStyle=\'rgba(255,215,0,0.6)\';ctx2.lineWidth=14;\n      ctx2.beginPath();ctx2.arc(256,256,249,0,Math.PI*2);ctx2.stroke();\n      const splashUrl=c2.toDataURL(\'image/png\');\n\n      const mf={name:\'Radha Naam Jap\',short_name:\'Radha Jap\',description:\'Jai Shri Radha\',\n        start_url:\'./index.html\',scope:\'./\',display:\'standalone\',orientation:\'portrait-primary\',\n        background_color:\'#060D1F\',theme_color:\'#060D1F\',\n        icons:[\n          {src:iconUrl,sizes:\'512x512\',type:\'image/png\',purpose:\'any maskable\'},\n          {src:iconUrl,sizes:\'192x192\',type:\'image/png\',purpose:\'any maskable\'}\n        ]};\n      const blob=new Blob([JSON.stringify(mf)],{type:\'application/manifest+json\'});\n      const lnk=document.createElement(\'link\');lnk.rel=\'manifest\';lnk.href=URL.createObjectURL(blob);document.head.appendChild(lnk);\n      document.querySelectorAll(\'link[rel*="icon"],link[rel="apple-touch-icon"]\').forEach(l=>l.remove());\n      const ati=document.createElement(\'link\');ati.rel=\'apple-touch-icon\';ati.sizes=\'512x512\';ati.href=splashUrl;document.head.appendChild(ati);\n      const ico=document.createElement(\'link\');ico.rel=\'icon\';ico.type=\'image/png\';ico.href=iconUrl;document.head.appendChild(ico);\n    }catch(e){console.warn(\'buildPwaManifest:\',e);}\n  }\n  if(img&&img.complete&&img.naturalWidth)attach();\n  else if(img)img.addEventListener(\'load\',attach);\n  else setTimeout(buildPwaManifest,200);\n}'

def patch(html):
    # 1. Replace splash image (Radha Ballabh deity)
    html = re.sub(
        r'<img class="ls-img" id="guruImg" src="data:image/jpeg;base64,[^"]*" alt="[^"]*">',
        f'<img class="ls-img" id="guruImg" src="data:image/jpeg;base64,{SPLASH_B64}" alt="Shri Radha Ballabh">',
        html, count=1
    )

    # 2. Add hidden icon img after <body>
    hidden = f'<img id="pwaIconImg" src="data:image/jpeg;base64,{ICON_B64}" style="display:none" alt="icon">'
    if 'pwaIconImg' not in html:
        html = html.replace('<body>', '<body>\n' + hidden, 1)

    # 3. Firebase auth: add fbWriteActiveSession call
    html = html.replace(
        "setSyncPill('syncing', 'Connecting\u2026');\n        fbAutoSync();",
        "setSyncPill('syncing', 'Connecting\u2026');\n        fbWriteActiveSession();\n        fbAutoSync();"
    , 1)

    # 4. Add fbWriteActiveSession function before fbAutoSync
    if 'fbWriteActiveSession' not in html or 'async function fbWriteActiveSession' not in html:
        html = html.replace('function fbAutoSync() {', FB_WRITE_SESSION, 1)

    # 5. One-device: patch fbApplyRemote
    old_apply = """function fbApplyRemote(d) {
  if (d.deviceId && d.deviceId === fbDeviceId) return;"""
    if 'ONE DEVICE AT A TIME' not in html:
        html = html.replace(old_apply, FB_APPLY_REMOTE, 1)

    # 6. fbPushFull: stamp activeSession
    old_payload_end = 'deviceId: fbDeviceId\n  };'
    new_payload_end = 'deviceId: fbDeviceId, activeSession: fbDeviceId\n  };'
    if 'activeSession: fbDeviceId' not in html:
        html = html.replace(old_payload_end, new_payload_end, 1)

    # 7. Replace buildPwaManifest with new version (uses pwaIconImg)
    html = re.sub(
        r'function buildPwaManifest\(\)\{.*?^}',
        PWA_MANIFEST,
        html, count=1, flags=re.DOTALL|re.MULTILINE
    )

    return html

if __name__ == '__main__':
    fn = sys.argv[1] if len(sys.argv) > 1 else 'index.html'
    with open(fn, encoding='utf-8') as f:
        html = f.read()
    patched = patch(html)
    out = fn.replace('.html', '_v6.html')
    with open(out, 'w', encoding='utf-8') as f:
        f.write(patched)
    print(f"✅ Written: {out}")
    # Verify
    checks = [
        ('Radha Ballabh', 'Splash image'),
        ('pwaIconImg', 'Icon img tag'),
        ('fbWriteActiveSession', 'Session write fn'),
        ('ONE DEVICE AT A TIME', 'Session eviction'),
        ('activeSession: fbDeviceId', 'Payload stamp'),
    ]
    for text, label in checks:
        print(f"  {'✅' if text in patched else '❌'} {label}")
